output.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?year(COUNT(*) AS ?wins) WHERE {
  VALUES(?season ?year) {(wd:Q28829 2008)(wd:Q1013269 2015)(wd:Q288299 2017)(wd:Q3420159 2018)(wd:Q3468243 2019)
  }
  ?season wdt:P154 ?race .
  ?race wdt:P125 wd:Q22865 .
}
GROUP BY ?year
ORDER BY DESC(?wins)

